package com.repoalvo.javaapi;

import com.repoalvo.javaapi.model.UserCreateRequest;
import com.repoalvo.javaapi.model.UserResponse;
import com.repoalvo.javaapi.model.UserUpdateRequest;
import com.repoalvo.javaapi.service.UserService;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.util.List;
import java.util.Optional;
import java.util.concurrent.*;
import java.util.stream.IntStream;

import static org.junit.jupiter.api.Assertions.*;

class UserServiceUnitTest {

    private UserService userService;

    @BeforeEach
    void setup() {
        userService = new UserService();
    }

    @Test
    void constructor_shouldInitializeStateViaReset() {
        List<UserResponse> users = userService.listAllUsers();
        assertEquals(2, users.size(), "Constructor should initialize with 2 default users");
        assertEquals(1, users.get(0).id());
        assertEquals(2, users.get(1).id());
    }

    @Test
    void reset_shouldClearUsersAndAddDefaultUsersAndResetNextId() {
        // Arrange: create a new user to change state
        UserCreateRequest newUser = new UserCreateRequest("Carlos", "carlos@example.com", "USER", "+55 11 90000-0003");
        userService.create(newUser);

        // Act
        userService.reset();

        // Assert
        List<UserResponse> users = userService.listAllUsers();
        assertEquals(2, users.size(), "Reset should leave exactly 2 default users");
        assertEquals(1, users.get(0).id());
        assertEquals("Ana Silva", users.get(0).name());
        assertEquals(2, users.get(1).id());
        assertEquals("Bruno Lima", users.get(1).name());

        // Confirm nextId reset to 3 by creating a new user and checking id
        UserResponse created = userService.create(newUser);
        assertEquals(3, created.id(), "nextId should be reset to 3 after reset");
    }

    @Test
    void crudOperations_beforeAndAfterReset_shouldBehaveConsistently() {
        // Before reset: create user
        UserCreateRequest newUser = new UserCreateRequest("Daniel", "daniel@example.com", null, "+55 11 90000-0004");
        UserResponse created = userService.create(newUser);
        assertNotNull(created);
        assertEquals("Daniel", created.name());

        // Update user
        UserUpdateRequest updateRequest = new UserUpdateRequest("Daniel Updated", null, "ADMIN", null);
        Optional<UserResponse> updatedOpt = userService.update(created.id(), updateRequest);
        assertTrue(updatedOpt.isPresent());
        assertEquals("Daniel Updated", updatedOpt.get().name());
        assertEquals("ADMIN", updatedOpt.get().role());

        // Delete user
        userService.delete(created.id());
        Optional<UserResponse> deleted = userService.getById(created.id());
        assertTrue(deleted.isEmpty());

        // After reset: state should be default
        userService.reset();
        List<UserResponse> users = userService.listAllUsers();
        assertEquals(2, users.size());

        // CRUD after reset
        UserCreateRequest newUser2 = new UserCreateRequest("Elisa", "elisa@example.com", "USER", "+55 11 90000-0005");
        UserResponse created2 = userService.create(newUser2);
        assertEquals(3, created2.id());

        Optional<UserResponse> found = userService.getById(created2.id());
        assertTrue(found.isPresent());
        assertEquals("Elisa", found.get().name());

        userService.delete(created2.id());
        assertTrue(userService.getById(created2.id()).isEmpty());
    }

    @Test
    void multipleResetCycles_shouldMaintainConsistentState() {
        IntStream.range(0, 5).forEach(i -> {
            userService.reset();
            List<UserResponse> users = userService.listAllUsers();
            assertEquals(2, users.size(), "Reset cycle " + i + " should have 2 default users");
            assertEquals(1, users.get(0).id());
            assertEquals(2, users.get(1).id());

            UserCreateRequest newUser = new UserCreateRequest("User" + i, "user" + i + "@example.com", null, null);
            UserResponse created = userService.create(newUser);
            assertEquals(3, created.id(), "After reset, nextId should start at 3");
        });
    }

    @Test
    void reset_calledConcurrently_shouldMaintainConsistentStateWithoutRaceConditions() throws InterruptedException, ExecutionException {
        int threadCount = 10;
        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
        CountDownLatch latch = new CountDownLatch(1);

        Callable<Void> resetTask = () -> {
            latch.await();
            userService.reset();
            return null;
        };

        List<Future<Void>> futures = new CopyOnWriteArrayList<>();
        for (int i = 0; i < threadCount; i++) {
            futures.add(executor.submit(resetTask));
        }

        latch.countDown(); // release all threads simultaneously

        for (Future<Void> future : futures) {
            future.get(); // wait for completion
        }

        executor.shutdown();

        // After concurrent resets, state should be consistent
        List<UserResponse> users = userService.listAllUsers();
        assertEquals(2, users.size(), "After concurrent resets, should have 2 default users");
        assertEquals(1, users.get(0).id());
        assertEquals(2, users.get(1).id());

        // nextId should be reset to 3
        UserCreateRequest newUser = new UserCreateRequest("Concurrent", "concurrent@example.com", null, null);
        UserResponse created = userService.create(newUser);
        assertEquals(3, created.id());
    }

    @Test
    void synchronizedMethods_calledConcurrently_shouldNotCauseDeadlockOrInconsistency() throws InterruptedException, ExecutionException {
        int threadCount = 20;
        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
        CountDownLatch latch = new CountDownLatch(1);

        Runnable task = () -> {
            try {
                latch.await();
                // Randomly call methods that are synchronized
                userService.listAllUsers();
                userService.listUsers(10, 0);
                userService.getById(1);
                userService.findByEmail("ana@example.com");
                userService.create(new UserCreateRequest("Test", "test@example.com", null, null));
                userService.update(1, new UserUpdateRequest("Ana Updated", null, null, null));
                userService.delete(2);
                userService.reset();
            } catch (InterruptedException ignored) {
            }
        };

        for (int i = 0; i < threadCount; i++) {
            executor.submit(task);
        }

        latch.countDown();
        executor.shutdown();
        boolean finished = executor.awaitTermination(10, TimeUnit.SECONDS);
        assertTrue(finished, "Executor should finish all tasks without deadlock");

        // After concurrent calls, state should be consistent
        List<UserResponse> users = userService.listAllUsers();
        assertNotNull(users);
        assertTrue(users.size() >= 0);
    }

    @Test
    void reset_shouldNotLeaveServiceInInconsistentStateOnException() {
        // Since reset() does not throw checked exceptions and no failure simulation is possible in current code,
        // we simulate by subclassing UserService to throw exception during reset and verify state consistency.

        class FaultyUserService extends UserService {
            private boolean throwOnClear = true;

            @Override
            public synchronized void reset() {
                if (throwOnClear) {
                    throwOnClear = false;
                    throw new RuntimeException("Simulated failure during reset");
                }
                super.reset();
            }
        }

        FaultyUserService faultyService = new FaultyUserService();

        // First call to reset throws exception
        RuntimeException ex = assertThrows(RuntimeException.class, faultyService::reset);
        assertEquals("Simulated failure during reset", ex.getMessage());

        // State should be as before reset call (likely default constructor state)
        List<UserResponse> usersBefore = faultyService.listAllUsers();
        assertFalse(usersBefore.isEmpty());

        // Second call to reset should succeed
        assertDoesNotThrow(faultyService::reset);
        List<UserResponse> usersAfter = faultyService.listAllUsers();
        assertEquals(2, usersAfter.size());
    }

    @Test
    void crudOperations_afterReset_shouldRejectOrHandleRequestsDependingOnOldData() {
        // Create user and get id
        UserCreateRequest newUser = new UserCreateRequest("OldUser", "olduser@example.com", null, null);
        UserResponse created = userService.create(newUser);
        int oldUserId = created.id();

        // Reset service
        userService.reset();

        // Old user id should not exist anymore
        Optional<UserResponse> oldUser = userService.getById(oldUserId);
        assertTrue(oldUser.isEmpty(), "Old user should not exist after reset");

        // Update old user should return empty optional
        Optional<UserResponse> updateResult = userService.update(oldUserId, new UserUpdateRequest("Name", null, null, null));
        assertTrue(updateResult.isEmpty(), "Update on old user id should return empty after reset");

        // Delete old user should not throw and not affect current users
        userService.delete(oldUserId);
        List<UserResponse> currentUsers = userService.listAllUsers();
        assertEquals(2, currentUsers.size(), "Delete of old user id should not affect current users");
    }
}
