        assertTrue(updatedOpt.isPresent());
        assertEquals("Daniel Updated", updatedOpt.get().name());
        assertEquals("ADMIN", updatedOpt.get().role());

        // Delete user
        userService.delete(created.id());
        Optional<UserResponse> deleted = userService.getById(created.id());
        assertTrue(deleted.isEmpty());

        // After reset: state should be default
        userService.reset();
        List<UserResponse> users = userService.listAllUsers();
        assertEquals(2, users.size());

