        UserCreateRequest newUser2 = new UserCreateRequest("Elisa", "elisa@example.com", "USER", "+55 11 90000-0005");
        UserResponse created2 = userService.create(newUser2);
        assertEquals(3, created2.id());

        Optional<UserResponse> found = userService.getById(created2.id());
        assertTrue(found.isPresent());
        assertEquals("Elisa", found.get().name());

        userService.delete(created2.id());
        assertTrue(userService.getById(created2.id()).isEmpty());
