    @Test
    void reset_calledConcurrently_shouldMaintainConsistentStateWithoutRaceConditions() throws InterruptedException, ExecutionException {
        int threadCount = 10;
        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
        CountDownLatch latch = new CountDownLatch(1);

        Callable<Void> resetTask = () -> {
            latch.await();
            userService.reset();
            return null;
        };

        List<Future<Void>> futures = new CopyOnWriteArrayList<>();
        for (int i = 0; i < threadCount; i++) {
            futures.add(executor.submit(resetTask));
        }

        latch.countDown(); // release all threads simultaneously

        for (Future<Void> future : futures) {
            future.get(); // wait for completion
        }

        executor.shutdown();

        // After concurrent resets, state should be consistent
        List<UserResponse> users = userService.listAllUsers();
        assertEquals(2, users.size(), "After concurrent resets, should have 2 default users");
        assertEquals(1, users.get(0).id());
        assertEquals(2, users.get(1).id());

