        class FaultyUserService extends UserService {
            private boolean throwOnClear = true;

            @Override
            public synchronized void reset() {
                if (throwOnClear) {
                    throwOnClear = false;
                    throw new RuntimeException("Simulated failure during reset");
                }
                super.reset();
            }
        }

