        userService.reset();
    }

    @Test
    @DisplayName("reset() should clear users and add exactly two default users with nextId reset to 3")
    void resetShouldInitializeDefaultUsersAndResetNextId() {
        // Arrange: add a user to change state
        userService.createUser("temp", "temp@example.com", "active", "user");

        // Act
        userService.reset();

        // Assert
        List<User> users = userService.getAllUsers();
        assertEquals(2, users.size(), "After reset, there should be exactly two default users");
        assertTrue(users.stream().anyMatch(u -> "ana@example.com".equals(u.getEmail())), "Default user ana@example.com should exist");
        assertTrue(users.stream().anyMatch(u -> "bob@example.com".equals(u.getEmail())), "Default user bob@example.com should exist");
        assertEquals(3, userService.getNextId(), "nextId should be reset to 3");
    }

    @Test
    @DisplayName("Constructor should initialize state via reset()")
    void constructorShouldInitializeState() {
        UserService newService = new UserService();
        List<User> users = newService.getAllUsers();
        assertEquals(2, users.size(), "Constructor should initialize with two default users");
        assertEquals(3, newService.getNextId(), "nextId should be initialized to 3");
    }

    @Test
    @DisplayName("CRUD operations before and after reset() should behave consistently")
    void crudOperationsBeforeAndAfterReset() {
        // Create user
        User created = userService.createUser("Charlie", "charlie@example.com", "active", "user");
        assertNotNull(created);
        assertEquals("charlie@example.com", created.getEmail());

        // Reset
        userService.reset();

        // After reset, user should not exist
        assertNull(userService.getUserByEmail("charlie@example.com"));

        // Create again after reset
        User createdAfterReset = userService.createUser("Charlie", "charlie@example.com", "active", "user");
        assertNotNull(createdAfterReset);
        assertEquals("charlie@example.com", createdAfterReset.getEmail());
    }

    @Test
    @DisplayName("Multiple reset() calls should be idempotent and consistent")
    void multipleResetsShouldBeIdempotent() {
        userService.createUser("temp", "temp@example.com", "active", "user");
        userService.reset();
        List<User> usersAfterFirstReset = userService.getAllUsers();

        userService.reset();
        List<User> usersAfterSecondReset = userService.getAllUsers();

        assertEquals(usersAfterFirstReset.size(), usersAfterSecondReset.size(), "User list size should be same after multiple resets");
        assertEquals(usersAfterFirstReset, usersAfterSecondReset, "User list should be identical after multiple resets");
        assertEquals(3, userService.getNextId(), "nextId should remain 3 after multiple resets");
    }

    @Test
    @DisplayName("reset() should clear all mutable state including users and nextId")
    void resetShouldClearAllMutableState() {
        userService.createUser("temp", "temp@example.com", "active", "user");
        userService.reset();

        assertEquals(2, userService.getAllUsers().size(), "Only default users should remain after reset");
        assertEquals(3, userService.getNextId(), "nextId should be reset to 3");
    }

    @Test
    @DisplayName("Simulate concurrent calls to reset() and createUser() to detect race conditions")
    void concurrentResetAndCreateUserShouldNotCauseInconsistencies() throws InterruptedException, ExecutionException {
        int threadCount = 10;
        ExecutorService executor = Executors.newFixedThreadPool(threadCount);

        Callable<Void> resetTask = () -> {
            userService.reset();
            return null;
        };

        Callable<Void> createTask = () -> {
            userService.createUser("Concurrent", "concurrent@example.com", "active", "user");
            return null;
        };

        // Mix reset and createUser calls concurrently
        List<Callable<Void>> tasks = IntStream.range(0, threadCount)
                .mapToObj(i -> (i % 2 == 0) ? resetTask : createTask)
                .toList();

        List<Future<Void>> futures = executor.invokeAll(tasks);

        // Await all tasks completion and check for exceptions
        for (Future<Void> future : futures) {
            future.get();
        }

        // After concurrent operations, state should be consistent
        List<User> users = userService.getAllUsers();
        assertNotNull(users);
        assertTrue(users.size() >= 2, "There should be at least the two default users after concurrent operations");

        // nextId should be >= 3
        assertTrue(userService.getNextId() >= 3, "nextId should be at least 3 after concurrent operations");

        executor.shutdown();
    }
}
